// ============================================================
// FIX: Parse Claude Message — soporta 3 formatos de mensaje
// A: bullets  "• _Label:_ valor"  (Legales)
// B: shortcodes ":red_circle: _Label_\ncontenido"  (Finance)
// C: emoji Unicode "🔍 Label\ncontenido"  (formato estándar)
// ============================================================
const rawText = $('Extract Event Data').item.json.message_text || '';
const text = rawText
  .replace(/<@[A-Z0-9]+\|[^>]+>/g, '')
  .replace(/<@[A-Z0-9]+>/g, '')
  .replace(/\*?Sent using\*?[^\n]*/g, '')
  .replace(/\*?Sent with\*?[^\n]*/g, '')
  .replace(/\*?Sent via\*?[^\n]*/g, '')
  .replace(/\*?Enviado[^\n]*/g, '')
  .trim();

const channel_id = $('Extract Event Data').item.json.channel_id || '';
const thread_ts  = $('Extract Event Data').item.json.thread_ts  || '';

const channelMap = {
  'C0AJ2599DA6': 'Finance & Accounting',
  'C0AJ67HK0ES': 'Legal & Compliance',
  'C0AK2PW5BGQ': 'Operations',
  'C0AKNPCNNSU': 'Sales & Partnerships',
  'C0AJMRFP0TD': 'Trading Desk',
  'C0ARDGP8134': 'Management'
};
const area = channelMap[channel_id] || '';

const extractBlock = (emojiLabel, bulletLabel, slackShortcodes) => {
  // Formato C: emoji Unicode bloque
  const emojiEscaped = emojiLabel.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const blockRegex = new RegExp(
    emojiEscaped + '\\s*\\n([\\s\\S]*?)(?=\\n:[a-z_]+:|\\n[\uD83D\uDD0D\uD83E\uDDED\u26A0\u2705\uD83D\uDEA8\uD83D\uDCCE\uD83D\uDC64]|$)',
    'i'
  );
  const blockMatch = text.match(blockRegex);
  if (blockMatch && blockMatch[1].trim()) return blockMatch[1].trim();

  // Formato B: shortcode de Slack bloque
  for (const sc of (slackShortcodes || [])) {
    const scEscaped = sc.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const scBlockRegex = new RegExp(
      scEscaped + '\\s*(?:_[^_]+_)?\\s*\\n([\\s\\S]*?)(?=\\n:[a-z_]+:|$)',
      'i'
    );
    const scMatch = text.match(scBlockRegex);
    if (scMatch && scMatch[1].trim()) return scMatch[1].trim();
  }

  // Formato A: bullet inline
  const bulletEscaped = bulletLabel.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const bulletRegex = new RegExp(
    '(?:\u2022\\s*_?' + bulletEscaped + ':?_?\\*?|\\*' + bulletEscaped + ':\\*)\\s*([^\\n]+)',
    'i'
  );
  const bulletMatch = text.match(bulletRegex);
  return bulletMatch ? bulletMatch[1].trim() : '';
};

const extractUrgencia = () => {
  const inline = text.match(/:(?:zap|rotating_light|alarm_clock)[^:]*:\s*_?Urgencia:?_?\s*([^\n]+)/i);
  if (inline) return inline[1].trim();
  const block = text.match(/:(?:zap|rotating_light|alarm_clock)[^:]*:\s*_?Urgencia_?\s*\n([^\n:]+)/i);
  if (block) return block[1].trim();
  const bullet = text.match(/[\u2022\-]\s*_?Urgencia:?_?\s*([^\n]+)/i);
  if (bullet) return bullet[1].trim();
  return '';
};

const solicitante = extractBlock('\uD83D\uDC64 Solicitante', 'Solicitante', [':bust_in_silhouette:']);
const problema    = extractBlock('\uD83D\uDD0D Problema',    'Problema',    [':red_circle:', ':mag:']);
const contexto    = extractBlock('\uD83E\uDDED Contexto',    'Contexto',    [':pushpin:', ':compass:']);
const impacto     = extractBlock('\u26A0\uFE0F Impacto',     'Impacto',     [':bar_chart:', ':warning:']);
const resultado   = extractBlock('\u2705 Resultado esperado','Resultado esperado', [':white_check_mark:']);
const urgencia    = extractUrgencia();

const problemaFull = problema + (contexto ? '\n\nContexto: ' + contexto : '');

const urgLower = (urgencia || '').toLowerCase();
let priority_id = '3';
if (urgLower.includes('cr\u00edtico') || urgLower.includes('critico')) priority_id = '1';
else if (urgLower.includes('alto')) priority_id = '2';
else if (urgLower.includes('bajo')) priority_id = '4';

const areaIdMap = {
  'Finance & Accounting': '10020',
  'Legal & Compliance':   '10021',
  'Operations':           '10022',
  'Sales & Partnerships': '10023',
  'Trading Desk':         '10024',
  'Management':           '10095'
};
const business_area_id = areaIdMap[area] || '';

const thread_url = 'https://arduasolutions.slack.com/archives/' + channel_id + '/p' + thread_ts.replace('.', '');

const rawSummary = '[Miles] ' + (area ? area + ' \u2014 ' : '') + problemaFull.replace(/\n/g, ' ');
const jira_summary = rawSummary.length > 150
  ? rawSummary.substring(0, rawSummary.lastIndexOf(' ', 150)) + '\u2026'
  : rawSummary;

return [{ json: {
  channel_id, thread_ts, area, solicitante,
  captured_area:      area,
  captured_problema:  problemaFull,
  captured_impacto:   impacto,
  captured_resultado: resultado,
  captured_urgencia:  urgencia,
  priority_id, business_area_id, thread_url, jira_summary
}}];

const msg = ($('Extract Event Data').item.json.message_text || '').toLowerCase().trim();

const channelMap = {
  'C0AJ2599DA6': 'Finance & Accounting',
  'C0AJ67HK0ES': 'Legal & Compliance',
  'C0AK2PW5BGQ': 'Operations',
  'C0AKNPCNNSU': 'Sales & Partnerships',
  'C0AJMRFP0TD': 'Trading Desk',
  'C0ARDGP8134': 'Management'
};
const channelId = $('Extract Event Data').item.json.channel_id || '';
const area = channelMap[channelId] || '';

const threadMessages = (() => {
  try { return $('Fetch Thread History').item.json.messages || []; }
  catch(e) { return []; }
})();

const botMessages = threadMessages.filter(m => m.bot_id);
const lastBotMsg = botMessages.length > 0 ? botMessages[botMessages.length - 1] : null;
const isConfirmationPending = lastBotMsg && (lastBotMsg.text || '').includes('este requerimiento');
const isAffirmative = /^(s[ií]|ok|dale|confirmo|correcto|listo|yes|sip|sep|afirmativo|claro)\s*[.!?,]*\s*$/i.test(msg);

if (isConfirmationPending && isAffirmative) {
  const summaryText = lastBotMsg.text || '';
  const extract = (label) => {
    const re = new RegExp('[•\\-]\\s*' + label + ':\\s*(.+)', 'i');
    const m = summaryText.match(re);
    return m ? m[1].trim() : '';
  };
  return [{ json: { ...$input.item.json, fast_intent: 'req-confirm', fast_issue_key: '', fast_area: area, confirm_area: extract('Área') || extract('Area'), confirm_problema: extract('Problema'), confirm_impacto: extract('Impacto'), confirm_resultado: extract('Resultado esperado'), confirm_urgencia: extract('Urgencia') }}];
}

const reqMatch = msg.match(/\breq-(\d+)\b/i);
if (reqMatch) return [{ json: { ...$input.item.json, fast_intent: 'req-status', fast_issue_key: 'REQ-' + reqMatch[1], fast_area: area } }];

if (/\b(ver|listar|mostrar|listado)\b/.test(msg) || /mis requerimientos|requerimientos del.rea|qu[eé] tickets|cu[aá]les son/.test(msg)) {
  return [{ json: { ...$input.item.json, fast_intent: 'req-list', fast_issue_key: '', fast_area: area } }];
}

return [{ json: { ...$input.item.json, fast_intent: '', fast_issue_key: '', fast_area: area } }];

const isClaude = (() => {
  try { return $('Parse Claude Message').item !== undefined; } catch(e) { return false; }
})();

let bp, pr;

if (isClaude) {
  pr = $('Parse Claude Message').first().json;
  bp = { jira_summary: pr.jira_summary, business_area_id: pr.business_area_id, priority_id: pr.priority_id, thread_url: pr.thread_url };
} else {
  bp = $('Build Jira Payload').first().json;
  pr = $('Parse AI Response').first().json;
}

const clean = (s) => (s || '').replace(/\n/g, ' ').replace(/\r/g, '').replace(/\t/g, ' ').trim() || '-';

const desc = {
  type: 'doc', version: 1,
  content: [
    { type: 'paragraph', content: [{ type: 'text', text: 'Capturado por Miles via Slack', marks: [{ type: 'em' }] }] },
    { type: 'paragraph', content: [{ type: 'text', text: '🔗 Ver hilo en Slack', marks: [{ type: 'link', attrs: { href: bp.thread_url } }] }] },
    { type: 'rule' },
    { type: 'heading', attrs: { level: 3 }, content: [{ type: 'text', text: 'Problema' }] },
    { type: 'paragraph', content: [{ type: 'text', text: clean(pr.captured_problema) }] },
    { type: 'heading', attrs: { level: 3 }, content: [{ type: 'text', text: 'Impacto' }] },
    { type: 'paragraph', content: [{ type: 'text', text: clean(pr.captured_impacto) }] },
    { type: 'heading', attrs: { level: 3 }, content: [{ type: 'text', text: 'Resultado esperado' }] },
    { type: 'paragraph', content: [{ type: 'text', text: clean(pr.captured_resultado) }] },
    { type: 'rule' },
    { type: 'paragraph', content: [{ type: 'text', text: 'Urgencia: ' + clean(pr.captured_urgencia) }] }
  ]
};

const fields = { project: { key: 'REQ' }, issuetype: { name: 'Requirement' }, summary: bp.jira_summary, priority: { id: bp.priority_id || '3' }, customfield_10171: { id: '10026' }, description: desc };

if (bp.business_area_id) fields.customfield_10170 = { id: bp.business_area_id };

return [{ json: { jira_body: JSON.stringify({ fields }) } }];

const msgs = ($json.messages || []);
const thread_ts = $('Extract Event Data').item.json.thread_ts;
const milesAlreadyReplied = msgs.some(m => m.bot_id && m.ts !== thread_ts);
return [{ json: { ...$json, is_duplicate: milesAlreadyReplied } }];

